def validate_coat_of_arms(elements):
    required_elements = {
        'starburst': False,
        'central_disc': False,
        'carpet_guls': 0,
        'akhal_teke_horse': False
    }

    for element in elements:
        if element == 'starburst':
            required_elements['starburst'] = True
        elif element == 'central_disc':
            required_elements['central_disc'] = True
        elif element.startswith('carpet_gul'):
            required_elements['carpet_guls'] += 1
        elif element == 'akhal_teke_horse':
            required_elements['akhal_teke_horse'] = True

    # Check all required elements are present
    if all(required_elements.values()) and required_elements['carpet_guls'] >= 5:
        return True
    return False

# Example usage:
coat_elements = ['starburst', 'central_disc', 'carpet_gul_teke', 'carpet_gul_yomut', 
                 'carpet_gul_arsary', 'carpet_gul_chowdur', 'carpet_gul_saryk', 'akhal_teke_horse']
print(validate_coat_of_arms(coat_elements))  # Output: True
